#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    cin >> n;    ll count_0 = 0, count_1 = 0;        vll a(n);    for(int i=0; i<n; i++){         cin >> a[i];         if(a[i] == 0) count_0++;         else if(a[i] == 1) count_1++;    }    ll ans = 1;    for(int i=1;i<=count_0;i++){        ans *= 2;      }    cout << ans*count_1 << "\n"; } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}